// // This module implements a 4-bit synchronous counter with a reset input. The counter decrements on the rising edge of the clock signal (aclk), and is reset to zero when the areset signal is high. When the counter reaches its minimum value of 0 (4'b0000), it rolls over to 15 and sets an underflow signal to indicate that a rollover has occurred. The underflow signal is cleared when the counter decrements correctly.
module top_module(
  input aclk,
  input areset,
  output reg [3:0] count,
  output reg overflow
);always @(posedge aclk) begin
    if (areset) begin
      count <= 4'b0000;
      overflow <= 1'b0;
    end
    else begin
      if (count == 4'b1111) begin
        count <= 4'b0000;
        overflow <= 1'b1;
      end
      else begin
        count <= count + 1;
        overflow <= 1'b0;
      end
    end
  end

endmodule
